SELECT (STR(YEAR(?date)) AS ?year) WHERE {
  wd:Q6392428 p:P1346 ?statement .
  ?statement ps:P1346 ?tournament .
  ?tournament wdt:P31 wd:Q916112 ;
            wdt:P585 ?date .
}
ORDER BY DESC(?date)
LIMIT 1

SELECT (STR(YEAR(?date)) AS ?year) WHERE {
  ?tournament wdt:P1346 wd:Q6392428 ;
              wdt:P585 ?date ;
              rdfs:label ?label .
  FILTER(LANG(?label) = 'en')
  FILTER(CONTAINS(LCASE(?label), 'ncaa'))
}
ORDER BY DESC(?date)
LIMIT 1

